query:
UPDATE conversation_sessions SET leadPhone = CONCAT('+1', leadPhone) WHERE leadPhone NOT LIKE '+%' AND LENGTH(leadPhone) = 10;
UPDATE conversation_sessions SET leadPhone = CONCAT('+', leadPhone) WHERE leadPhone NOT LIKE '+%' AND LENGTH(leadPhone) = 11 AND LEFT(leadPhone, 1) = '1';
SELECT id, leadPhone, leadName, stage FROM conversation_sessions ORDER BY createdAt DESC LIMIT 5;

